if (!function_exists('fin_t')) {
  function fin_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('fin_h')) {
  function fin_h($key, $fallback = '') { return htmlspecialchars((string) fin_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('fin_js')) {
  function fin_js($key, $fallback = '') { return json_encode(fin_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
require_once "incoming_payment_lib.php";
function ip_rows($q){$r=array();foreach($q as $x)$r[]=$x;return $r;}
$customers=ip_rows($db->query("SELECT kode_pemasok,nama FROM customer WHERE kode_pemasok IS NOT NULL ORDER BY nama"));
$invoices=ip_rows($db->query("SELECT si.id_sales,si.no_sales_invoice,si.invoice_no,si.bill_to,COALESCE(c.nama,si.bill_to) customer_name,si.gross_amount,COALESCE((SELECT SUM(amount) FROM erp_incoming_payment ip WHERE ip.sales_invoice_id=si.id_sales AND ip.status='POSTED'),0) paid_amount FROM sales_invoice si LEFT JOIN customer c ON c.kode_pemasok=si.bill_to WHERE si.billing_status IN ('POSTED','DRAFT') ORDER BY si.invoice_date DESC LIMIT 500"));
$bankAccounts=ip_rows($db->query("SELECT r.no_rek,r.nama_rek FROM rekening r LEFT JOIN rekening c ON c.induk=r.no_rek WHERE c.no_rek IS NULL AND (r.no_rek LIKE '112%' OR r.nama_rek LIKE '%Bank%' OR r.nama_rek LIKE '%Giro%') ORDER BY r.no_rek"));
$arAccounts=ip_rows($db->query("SELECT r.no_rek,r.nama_rek FROM rekening r LEFT JOIN rekening c ON c.induk=r.no_rek WHERE c.no_rek IS NULL AND (r.no_rek LIKE '121%' OR r.nama_rek LIKE '%Piutang%') ORDER BY r.no_rek"));
$currencies=ip_rows($db->query("SELECT jenis_valas FROM matauang GROUP BY jenis_valas ORDER BY jenis_valas='IDR' DESC, jenis_valas"));
?>
