<div class="modal fade" id="ip_detail_modal"><div class="modal-dialog modal-lg"><div class="modal-content"><div class="modal-header bg-primary"><button type="button" class="close" data-dismiss="modal">&times;</button><h4>Incoming Payment Detail</h4></div><div class="modal-body" id="ip_detail_body"></div></div></div></div>
<script>
$(function(){ $('.input-group.date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});$('.select2-filter').select2({width:'100%',allowClear:true,placeholder:'All'});var ipTable=null;function initSel(){$('.select2-modal').select2({width:'100%',dropdownParent:$('#ip_modal'),allowClear:true});}function params(){return{start_date:$('#start_date').val(),end_date:$('#end_date').val(),status:$('#filter_status').val(),customer_code:$('#filter_customer_code').val()};}function rebuildIpTable(){if(ipTable){ipTable.destroy();}ipTable=$('#ip_table').DataTable({pageLength:25,order:[[1,'desc']],dom:'Bfrtip',buttons:[{extend:'excelHtml5',text:'<i class="fa fa-file-excel-o"></i> Excel',className:'btn btn-success btn-sm',title:'Incoming Payment'},{extend:'print',text:'<i class="fa fa-print"></i> Print',className:'btn btn-default btn-sm',title:'Incoming Payment'}],columnDefs:[{targets:[9],className:'text-right'},{targets:[11],orderable:false,searchable:false,className:'text-center'}]});}function loadData(){if(ipTable){ipTable.destroy();ipTable=null;}$('#ip_table tbody').html('<tr><td colspan="12" class="text-center">Loading...</td></tr>');$.post('<?=base_admin();?>modul/incoming_payment/incoming_payment_action.php?act=filter',params(),function(r){if(r.status==='success'){$('#ip_table tbody').html(r.html);$('#kpi_total').text(r.total);$('#kpi_posted').text(r.posted);$('#kpi_draft').text(r.draft);$('#kpi_count').text(r.count);rebuildIpTable();}else{$('#ip_table tbody').html('<tr><td colspan="12" class="text-danger text-center">'+r.message+'</td></tr>');}},'json');}
$('#btn_filter').on('click',loadData);$('#btn_reset').on('click',function(){$('#ip_filter')[0].reset();$('.select2-filter').val('').trigger('change');$('#start_date').val('<?=date('Y-m-01');?>');$('#end_date').val('<?=date('Y-m-d');?>');loadData();});$('#btn_add').on('click',function(){$('#ip_form')[0].reset();$('#id').val('');$('#document_date,#posting_date,#value_date').val('<?=date('Y-m-d');?>');$('#kurs').val('1');$.getJSON('<?=base_admin();?>modul/incoming_payment/incoming_payment_action.php?act=get_no',function(r){$('#incoming_payment_no').val(r.no);});$('#ip_modal').modal('show');initSel();});
$('#sales_invoice_id').on('change',function(){var o=$(this).find(':selected');$('#customer_code').val(o.data('customer')).trigger('change');$('#sales_invoice_no').val(o.data('no'));if(o.data('open'))$('#amount').val(o.data('open'));});
$(document).on('click','.ip-save',function(){var act=$(this).data('act');$.post('<?=base_admin();?>modul/incoming_payment/incoming_payment_action.php?act='+act,$('#ip_form').serialize(),function(r){if(r.status==='success'){Swal.fire('Berhasil',r.message,'success');$('#ip_modal').modal('hide');loadData();}else Swal.fire('Gagal',r.message,'error');},'json');});
$(document).on('click','.ip-edit',function(){$.getJSON('<?=base_admin();?>modul/incoming_payment/incoming_payment_action.php?act=get&id='+$(this).data('id'),function(r){if(r.status!=='success'){Swal.fire('Gagal',r.message,'error');return;}var d=r.data;$('#ip_form')[0].reset();$.each(d,function(k,v){$('#'+k).val(v);});$('#id').val(d.id);$('#ip_modal').modal('show');initSel();$('.select2-modal').trigger('change');});});
$(document).on('click','.ip-detail',function(){$('#ip_detail_modal').modal('show');$('#ip_detail_body').html(<?=fin_js('common_loading', 'Loading...');?>);$.getJSON('<?=base_admin();?>modul/incoming_payment/incoming_payment_action.php?act=detail&id='+$(this).data('id'),function(r){$('#ip_detail_body').html(r.status==='success'?r.html:'<div class="alert alert-danger">'+r.message+'</div>');});});
$(document).on('click','.ip-post',function(){var id=$(this).data('id');Swal.fire({title:'Post incoming payment?',icon:'question',showCancelButton:true}).then(function(x){if(x.isConfirmed){$.post('<?=base_admin();?>modul/incoming_payment/incoming_payment_action.php?act=post',{id:id},function(r){r.status==='success'?Swal.fire('Berhasil',r.message,'success'):Swal.fire('Gagal',r.message,'error');loadData();},'json');}});});$('#btn_excel').on('click',function(){window.open('<?=base_admin();?>modul/incoming_payment/incoming_payment_action.php?act=excel&'+$.param(params()));});loadData();});
</script>
